const roleLocals = new Set(['info','sales','contact','support','hello','hi','admin','noreply','no-reply','careers','jobs','legal','privacy','abuse','postmaster','webmaster','marketing']);
function djb2(str) {
  let h = 5381;
  for (let i = 0; i < str.length; i++) h = ((h << 5) + h + str.charCodeAt(i)) | 0;
  return (h >>> 0).toString(16).padStart(8, '0');
}
return $input.all().map(item => {
  const body = item.json.body || item.json;
  const email = String(body.email || '').trim().toLowerCase();
  const companyDomain = String(body.company_domain || body.domain || '').trim().toLowerCase().replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/$/, '');
  const validEmail = /^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email);
  const validDomain = /^[a-z0-9.-]+\.[a-z]{2,}$/i.test(companyDomain);
  const emailLocal = validEmail ? email.split('@')[0] : '';
  const emailDomain = validEmail ? email.split('@')[1] : '';
  const eventHash = djb2(`${email}|${companyDomain}|${Date.now()}`);
  return { json: {
    received_at: new Date().toISOString(),
    raw_payload: body,
    email,
    company_domain: companyDomain,
    email_local: emailLocal,
    email_domain: emailDomain,
    valid_email: validEmail,
    valid_domain: validDomain,
    role_account: roleLocals.has(emailLocal),
    event_hash: eventHash
  }};
});

const pages = $input.all().map(item => {
  const j = item.json || {};
  const markdown = j.markdown || j.text || j.content || '';
  return {
    url: j.url || j.loadedUrl || null,
    title: j.metadata?.title || j.pageTitle || j.title || null,
    markdown: String(markdown).slice(0, 6000)
  };
}).filter(p => p.markdown.length > 0);
const totalChars = pages.reduce((s, p) => s + p.markdown.length, 0);
return [{ json: { apify_pages: pages, apify_page_count: pages.length, apify_total_chars: totalChars, website_unresolved: pages.length === 0 || totalChars < 200 } }];

return $input.all().map(item => {
  const n = $('Normalize Lead').first().json;
  // CRITICAL FIX: read Apollo Org + People directly from upstream nodes
  // (the Merge node loses Apollo Org data when Apollo People errors).
  const orgRaw = (()=>{ try { return $('Apollo Organization Enrich').first().json || {}; } catch(e) { return {}; } })();
  const peopleRaw = (()=>{ try { return $('Apollo People Search').first().json || {}; } catch(e) { return {}; } })();
  const apifySum = (()=>{ try { return $('Summarize Website Crawl').first().json || {}; } catch(e) { return {}; } })();
  const org = orgRaw.organization || orgRaw.apollo_organization || {};
  const topPeople = Array.isArray(peopleRaw.people) ? peopleRaw.people : Array.isArray(peopleRaw.contacts) ? peopleRaw.contacts : Array.isArray(peopleRaw.organization_top_people) ? peopleRaw.organization_top_people : [];
  const apolloPeopleError = peopleRaw.error_code || peopleRaw.error || null;
  const email = n.email;
  const matchedPerson = topPeople.find(p => String(p.email || p.work_email || '').toLowerCase() === email) || null;
  const emailMatched = !!matchedPerson;
  const techStack = Array.isArray(org.technologies) ? org.technologies.map(t => typeof t === 'string' ? t : t?.name).filter(Boolean) : [];
  const industries = Array.isArray(org.industries) ? org.industries : [];
  const keywords = Array.isArray(org.keywords) ? org.keywords : [];
  const pages = apifySum.apify_pages || [];
  const pageText = pages.map(p => `${p.title || ''}\n${p.markdown || ''}`).join('\n\n').slice(0, 16000);
  const websiteUnresolved = !!apifySum.website_unresolved;
  const enrichmentInconsistent = n.email_domain && n.company_domain && n.email_domain !== n.company_domain && !['gmail.com','outlook.com','hotmail.com','yahoo.com','icloud.com','proton.me','protonmail.com'].includes(n.email_domain);
  const thinTriggers = [];
  if (!org.short_description || String(org.short_description).length < 100) thinTriggers.push('missing_or_short_description');
  if (!org.estimated_num_employees) thinTriggers.push('missing_company_size');
  if (!org.industry && industries.length === 0) thinTriggers.push('missing_industry');
  if (!emailMatched || !matchedPerson?.title) thinTriggers.push('missing_confirmed_decision_maker');
  if ((apifySum.apify_total_chars || 0) < 500) thinTriggers.push('thin_website');
  if (websiteUnresolved) thinTriggers.push('website_unresolved');
  const apolloHasOrgData = !!(org.name || org.industry || org.estimated_num_employees);
  const dataTier = (apolloHasOrgData && org.industry && org.estimated_num_employees && emailMatched && !websiteUnresolved && (apifySum.apify_total_chars || 0) >= 500) ? 'RICH' : (apolloHasOrgData || (apifySum.apify_total_chars || 0) >= 500 ? 'PARTIAL' : 'MINIMAL');
  const combined = {
    email: n.email,
    company_domain: n.company_domain,
    company_name: org.name || null,
    industry: org.industry || (industries[0] || null),
    industries_list: industries,
    apollo_keywords: keywords,
    estimated_num_employees: org.estimated_num_employees || null,
    country: org.country || null,
    city: org.city || null,
    short_description: org.short_description || null,
    tech_stack: techStack,
    latest_funding_stage: org.latest_funding_stage || null,
    latest_funding_round_date: org.latest_funding_round_date || null,
    total_funding_printed: org.total_funding_printed || null,
    founded_year: org.founded_year || null,
    person_first_name: matchedPerson?.first_name || null,
    person_last_name: matchedPerson?.last_name || null,
    person_title: matchedPerson?.title || null,
    person_seniority: matchedPerson?.seniority || null,
    email_matched_in_top_people: emailMatched,
    apollo_people_unavailable: !!apolloPeopleError,
    website_pages_count: pages.length,
    website_total_chars: apifySum.apify_total_chars || 0,
    website_excerpt: pageText.slice(0, 6000),
    thin_data_triggers: thinTriggers
  };
  const context = JSON.stringify(combined, null, 2);
  return { json: {
    ...n,
    apollo_organization: org,
    apollo_top_people: topPeople,
    apollo_people_unavailable: !!apolloPeopleError,
    email_matched_in_top_people: emailMatched,
    matched_person: matchedPerson,
    apify_content: pages,
    website_unresolved: websiteUnresolved,
    enrichment_inconsistent: enrichmentInconsistent,
    combined_enrichment: combined,
    combined_enrichment_text: context,
    thin_data_triggers: thinTriggers,
    data_tier: dataTier
  }};
});

