const base = $('Build Enrichment Context').first().json;
const agentRaw = $('Agent Research Gap Filler').first().json || {};
const scoreRaw = $('ICP Scoring').first().json || {};
const agent = agentRaw.output || agentRaw;
const score = scoreRaw.output || scoreRaw;
return $input.all().map(item => {
  const emailRaw = item.json || {};
  const email = emailRaw.output || emailRaw;
  const expectedFromSubtotal = (subtotal) => subtotal <= 2 ? 2 : subtotal <= 4 ? 3 : subtotal === 5 ? 4 : subtotal <= 7 ? 5 : subtotal <= 9 ? 6 : subtotal === 10 ? 7 : subtotal === 11 ? 8 : subtotal <= 13 ? 9 : 10;
  const subtotal = Number(score.subtotal || 0);
  const finalScore = Number(score.final_score || 0);
  const expected = expectedFromSubtotal(subtotal);
  const anomaly = Math.abs(finalScore - expected) > 2 && !(score.disqualifiers_triggered || []).includes('competitor_not_prospect');
  const tier = score.tier || (finalScore >= 8 ? 'hot' : finalScore >= 4 ? 'warm' : 'cold');
  const template = tier === 'hot' ? (base.data_tier === 'RICH' ? 'hot_rich' : 'hot_short') : tier === 'warm' ? 'warm' : (email.action === 'skip' ? 'cold_skip' : 'cold_drip');
  return { json: {
    email: base.email,
    company_domain: base.company_domain,
    role_account: !!base.role_account,
    enrichment_inconsistent: !!base.enrichment_inconsistent,
    website_unresolved: !!base.website_unresolved,
    apollo_organization: base.apollo_organization || {},
    apollo_top_people: base.apollo_top_people || [],
    email_matched_in_top_people: !!base.email_matched_in_top_people,
    matched_person: base.matched_person || null,
    apify_content: base.apify_content || [],
    combined_enrichment: base.combined_enrichment || {},
    data_tier: base.data_tier || 'MINIMAL',
    agent_iterations: agent.iterations_used || 0,
    agent_tools_called: agent.tools_called || [],
    agent_has_enough_info: !!agent.has_enough_info,
    agent_findings: agent.additional_findings || {},
    agent_research_reasoning: agent.research_reasoning || '',
    criteria_scores: score.criteria_scores || [],
    disqualifiers_triggered: score.disqualifiers_triggered || [],
    subtotal,
    expected_score: expected,
    final_score: finalScore || null,
    tier,
    summary_reasoning: score.summary_reasoning || '',
    evidence_fabricated: {},
    evidence_fabrication: false,
    score_anomaly: anomaly,
    email_subject: email.subject || null,
    email_body: email.body || null,
    email_template_used: template,
    action_taken: email.action === 'skip' ? 'skipped_disqualifier' : 'email_drafted',
    review_reason: anomaly ? 'score_anomaly' : null,
    total_cost_usd: null,
    total_latency_ms: Date.now() - new Date(base.received_at).getTime(),
    llm_calls_count: 2 + (agent.iterations_used || 0),
    event_hash: base.event_hash,
    reviewer_summary: `${String(tier).toUpperCase()} score ${finalScore || 'n/a'}: ${score.summary_reasoning || ''}`
  }};
});
